  {
    "file": "src/vs/base/common/strings.ts",
    "line": 215,
    "severity": "critical",
    "description": "Incorrect word boundary character in wholeWord regex construction. The code checks for '\B' (non-word boundary) instead of '\b' (word boundary) when determining if a word boundary already exists. This breaks whole-word search matches because it tests for the opposite boundary type, causing word boundaries to be added incorrectly or not at all. For example, searching for 'test' with wholeWord=true will generate incorrect patterns that don't properly match whole word occurrences.",
    "fix_patch": "--- a/src/vs/base/common/strings.ts
+++ b/src/vs/base/common/strings.ts
@@ -212,11 +212,11 @@ export function createRegExp(searchString: string, isRegex: boolean, options: R
 		searchString = escapeRegExpCharacters(searchString);
 	}
 	if (options.wholeWord) {
-		if (!/\\B/.test(searchString.charAt(0))) {
+		if (!/\\b/.test(searchString.charAt(0))) {
 			searchString = '\\\\b' + searchString;
 		}
-		if (!/\\B/.test(searchString.charAt(searchString.length - 1))) {
+		if (!/\\b/.test(searchString.charAt(searchString.length - 1))) {
 			searchString = searchString + '\\\\b';
 		}
 	}
"
  },
